// client/src/components/Header.jsx
import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import SearchBar from './SearchBar'; // Import SearchBar
import './Header.css';

const Header = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const handleSearch = (query) => {
        // Navigate to the products page with the search query as a URL parameter
        if (query) {
            navigate(`/products?keyword=${encodeURIComponent(query)}`);
        } else {
            navigate('/products'); // Navigate to products page without a keyword if query is empty
        }
    };

    return (
        <header className="header">
            <div className="header-container">
                <Link to="/" className="logo">My Electroo</Link>
                <div className="header-search"> {/* New wrapper for search bar */}
                    <SearchBar onSearch={handleSearch} />
                </div>
                <nav className="nav-links">
                    <Link to="/products">Products</Link>
                    <Link to="/cart">Cart</Link>
                    {user ? (
                        <>
                            <Link to="/profile">Profile</Link>
                            {user.role === 'admin' && <Link to="/admin">Admin</Link>}
                            <button onClick={handleLogout} className="nav-btn">Logout</button>
                        </>
                    ) : (
                        <>
                            <Link to="/login">Login</Link>
                            <Link to="/register">Register</Link>
                        </>
                    )}
                </nav>
            </div>
        </header>
    );
};

export default Header;
